const staticData = $getWorkflowStaticData('node');
staticData.results = [];
staticData.token = $('Umami Login').first().json.token;
staticData.startAt = $('Set Date Range').first().json.start_7d;
staticData.endAt = $('Set Date Range').first().json.end_now;
staticData.reportDate = $('Set Date Range').first().json.report_date;

const sites = [
  {id: 'dc9840ac-15ff-4c35-b210-7ab9c46a6867', name: 'THA', domain: 'thehockeyanalytics.com', niche: 'Hockey analytics SaaS'},
  {id: 'cda4abee-7b6b-490e-bc60-a42307d764cb', name: 'THB', domain: 'thehockeybrain.com', niche: 'Hockey consulting'},
  {id: 'fc8f279b-0da8-4013-b8df-be07dc12a8f1', name: 'TUR', domain: 'theunnamedroads.com', niche: 'AI venture studio flagship'},
  {id: 'b860bcc1-2a7a-4436-97f3-a2cb41b273c6', name: 'EIK', domain: 'emilingemarkarlsson.com', niche: 'AI consulting personal brand'},
  {id: '61956d72-33b2-4663-849c-5874b312984d', name: 'TAN', domain: 'tan-website.netlify.app', niche: 'AI agent services'},
  {id: '9438eb5d-4409-47fd-893f-105c80e1dd5e', name: 'TAF', domain: 'tur-theagentfabric.vercel.app', niche: 'AI automation content'},
  {id: '4b9cfa68-52aa-417a-906b-a87b041486ba', name: 'TPR', domain: 'theprintroute.com', niche: 'B2B print platform'},
  {id: '472ea0eb-c7de-4176-85fe-96fc218c9bea', name: 'FIN', domain: 'finnbodahamnplan.se', niche: 'Swedish local'}
];

return sites.map(s => ({json: s}));

const staticData = $getWorkflowStaticData('node');
const stats = $input.item.json;
const site = $('Loop Sites').item.json;

const pv = stats.pageviews?.value ?? stats.pageviews ?? 0;
const vis = stats.visitors?.value ?? stats.visitors ?? 0;
const sess = stats.sessions?.value ?? stats.sessions ?? 0;
const bounces = stats.bounces?.value ?? stats.bounces ?? 0;

staticData.results.push({
  name: site.name,
  domain: site.domain,
  niche: site.niche,
  pageviews: pv,
  visitors: vis,
  sessions: sess,
  bounces: bounces
});

return [{json: {accumulated: staticData.results.length}}];

const staticData = $getWorkflowStaticData('node');
const results = (staticData.results || []).slice();
const reportDate = staticData.reportDate || new Date().toISOString().split('T')[0];

results.sort((a, b) => b.pageviews - a.pageviews);

let md = '# Analytics Insights — Last 7 Days\n';
md += '_Generated: ' + reportDate + ' at 07:45_\n\n';
md += '## Site Performance Ranking\n\n';
md += '| Rank | Site | Domain | Pageviews | Visitors | Sessions |\n';
md += '|------|------|--------|-----------|----------|----------|\n';

results.forEach((r, i) => {
  md += '| ' + (i+1) + ' | **' + r.name + '** | ' + r.domain + ' | ' + r.pageviews + ' | ' + r.visitors + ' | ' + r.sessions + ' |\n';
});

const top3 = results.slice(0, 3);
const bottom = results.filter(r => r.pageviews < 20);
const noTraffic = results.filter(r => r.pageviews === 0);

md += '\n## CMO: Recommended Actions\n';
md += '- **Double down on**: ' + top3.map(r => r.name + ' (' + r.pageviews + ' pvs)').join(', ') + '\n';
md += '- **Trigger extra articles for top sites** — more content on what is already working\n';
if (bottom.length > 0) {
  md += '- **Sites needing attention** (< 20 pvs/7d): ' + bottom.map(r => r.name).join(', ') + '\n';
}
if (noTraffic.length > 0) {
  md += '- **Zero traffic sites**: ' + noTraffic.map(r => r.name).join(', ') + ' — investigate or skip\n';
}

md += '\n## CEO: Portfolio Signals\n';
md += '- Top earner potential: **' + (top3[0]?.name || 'TUR') + '** — ' + (top3[0]?.pageviews || 0) + ' pageviews\n';
md += '- Traffic concentration: top 3 sites = ' + top3.reduce((s,r) => s+r.pageviews, 0) + ' of ' + results.reduce((s,r) => s+r.pageviews, 0) + ' total pageviews\n';
md += '- Sites with zero traction: consider pausing content generation for zero-traffic sites\n';

md += '\n## CTO: Technical Signals\n';
md += '- Subdomains with traffic penalty: TAN (netlify), TAF (vercel) — domain migration priority confirmed\n';
if (noTraffic.length > 0) {
  md += '- Zero-traffic sites may have deployment issues: check ' + noTraffic.map(r => r.name).join(', ') + '\n';
}
md += '- All 8 Umami trackers confirmed working\n';

md += '\n---\n_Source: Umami analytics | Updated daily | agent-analytics-feed workflow_\n';

return [{json: {markdown: md, reportDate, totalPageviews: results.reduce((s,r) => s+r.pageviews, 0)}}];

const markdown = $json.markdown;
const buffer = Buffer.from(markdown, 'utf-8');
const binaryData = await this.helpers.prepareBinaryData(buffer, 'agent-analytics-context.md', 'text/markdown');
return [{
  json: {reportDate: $json.reportDate, totalPageviews: $json.totalPageviews},
  binary: {data: binaryData}
}];
